+    /// Batched router with top-K selection (process all tokens in parallel)
+    fn routerTopK_Q8_Batched(
+        self: *Self,
+        cmd_buffer: objc.MTLCommandBuffer,
+        router_weights_q8: objc.MTLBuffer,
+        batch_size: u32,
+        n_expert: u32,
+        n_embd: u32,
+    ) !void {
+        // Step 1: Compute router logits for all batch items in parallel
+        const encoder1 = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            return error.MetalEncoderCreationFailed;
+        };
+        defer objc.release(encoder1);
+
+        objc.encoderSetPipelineState(encoder1, self.pipeline_router_logits);
+        objc.encoderSetBuffer(encoder1, self.buf_hidden_states, 0, 0);
+        objc.encoderSetBuffer(encoder1, router_weights_q8, 0, 1);
+        objc.encoderSetBuffer(encoder1, self.buf_router_logits, 0, 2);
+        objc.encoderSetBytes(encoder1, @ptrCast(&batch_size), @sizeOf(u32), 3);
+        objc.encoderSetBytes(encoder1, @ptrCast(&n_expert), @sizeOf(u32), 4);
+        objc.encoderSetBytes(encoder1, @ptrCast(&n_embd), @sizeOf(u32), 5);
+
+        // Dispatch 2D grid: (batch_size, n_expert)
+        const grid_size1 = objc.MTLSize{ .width = batch_size, .height = n_expert, .depth = 1 };
+        const threadgroup_size1 = objc.MTLSize{ .width = 1, .height = @min(n_expert, 8), .depth = 1 };
+        objc.encoderDispatchThreads(encoder1, grid_size1, threadgroup_size1);
+        objc.encoderEndEncoding(encoder1);
+
+        // Step 2: Top-K selection for each batch item (parallel across batch)
+        const encoder2 = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            return error.MetalEncoderCreationFailed;
+        };
+        defer objc.release(encoder2);
+
