+    /// Batched expert FFN: process all tokens in parallel (10x faster!)
+    fn expertFFN_Q8_Batched(
+        self: *Self,
+        cmd_buffer: objc.MTLCommandBuffer,
+        input: objc.MTLBuffer,                  // [batch_size, n_embd]
+        gate_weights_q8: objc.MTLBuffer,
+        up_weights_q8: objc.MTLBuffer,
+        down_weights_q8: objc.MTLBuffer,
+        output: objc.MTLBuffer,                 // [batch_size, n_embd]
+        batch_size: u32,
+        n_embd: u32,
+        n_ff: u32,
+    ) !void {
+        const activated_buf = self.buf_intermediate;
+
+        // Pass 1: Compute gate/up projections + SwiGLU for ALL batch items in parallel
+        {
+            const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+                return error.MetalEncoderCreationFailed;
+            };
+            defer objc.release(encoder);
+
+            objc.encoderSetPipelineState(encoder, self.pipeline_expert_q8_0);
+            objc.encoderSetBuffer(encoder, input, 0, 0);
+            objc.encoderSetBuffer(encoder, gate_weights_q8, 0, 1);
+            objc.encoderSetBuffer(encoder, up_weights_q8, 0, 2);
+            objc.encoderSetBuffer(encoder, down_weights_q8, 0, 3);
+            objc.encoderSetBuffer(encoder, activated_buf, 0, 4);  // gate_buf
+            objc.encoderSetBuffer(encoder, self.buf_intermediate, 0, 5);  // up_buf (unused)
+            objc.encoderSetBuffer(encoder, output, 0, 6);
+            objc.encoderSetBytes(encoder, @ptrCast(&batch_size), @sizeOf(u32), 7);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_embd), @sizeOf(u32), 8);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_ff), @sizeOf(u32), 9);
+
+            // Dispatch 3D: (batch_size, n_ff, 1) with 32 threads per group
+            const threadgroups = objc.MTLSize{ .width = batch_size, .height = n_ff, .depth = 1 };
+            const threads_per_group = objc.MTLSize{ .width = 1, .height = 32, .depth = 1 };
+            objc.encoderDispatchThreadgroups(encoder, threadgroups, threads_per_group);
+            objc.encoderEndEncoding(encoder);
+        }
+
+        // Pass 2: Down projection for ALL batch items in parallel
+        {
+            const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+                return error.MetalEncoderCreationFailed;
+            };
+            defer objc.release(encoder);
+
+            objc.encoderSetPipelineState(encoder, self.pipeline_down_proj_q8_0);
+            objc.encoderSetBuffer(encoder, down_weights_q8, 0, 0);
+            objc.encoderSetBuffer(encoder, activated_buf, 0, 1);
+            objc.encoderSetBuffer(encoder, output, 0, 2);
+            objc.encoderSetBytes(encoder, @ptrCast(&batch_size), @sizeOf(u32), 3);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_embd), @sizeOf(u32), 4);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_ff), @sizeOf(u32), 5);
+
+            // Dispatch 3D: (batch_size, n_embd, 1) with 32 threads per group
+            const threadgroups = objc.MTLSize{ .width = batch_size, .height = n_embd, .depth = 1 };
+            const threads_per_group = objc.MTLSize{ .width = 1, .height = 32, .depth = 1 };
+            objc.encoderDispatchThreadgroups(encoder, threadgroups, threads_per_group);
+            objc.encoderEndEncoding(encoder);
+        }
+    }
